   * `expandableLayout` switch (details/grid/tabs/timeline/gallery/card/stats).
   *
   * Resolution order:
   *   config.renderExpandedRow → expandableLayout switch → "details" layout
   */
  renderExpandedRow?: ExpandedRowRenderer;

  /**
   * Typed JSX renderer for the pagination bar. Overrides the built-in
   * `paginationLayout` switch (full/compact/minimal/numbered/infoOnly).
   *
   * Resolution order:
   *   config.renderPagination → <DefaultPaginationBar /> (paginationLayout switch)
   */
  renderPagination?: PaginationRenderer;
}

/** HTTP method for either the list endpoint or per-row mutations. */
export type TableHttpMethod = "GET" | "POST" | "PUT" | "PATCH" | "DELETE";

export interface TableApiConfig {
  /** Base URL. e.g. "https://api.example.com/users" */
  baseUrl: string;
  /** HTTP method used to fetch the list. GET is recommended. */
  listMethod: TableHttpMethod;
  /**
   * Optional path template appended to baseUrl. Tokens:
   *   :id        — replaced with row.id (only for row mutations).
   *   :{field}   — replaced with the matching row field.
   * Example list path: "" or "/search". Example mutation path: "/:id".
   */
  listPath?: string;
  /** Extra query string parameters always sent with the list request. */
  listQuery?: Record<string, string>;
  /**
   * Body sent on non-GET list requests. Variables {{search}}, {{page}},
   * {{pageSize}}, {{filters}}, {{sort}} are interpolated by the hook.
   */
  listBody?: string;
  /** Optional headers (Bearer, x-api-key, etc.). */
  headers?: Record<string, string>;
  /**
   * Per-feature row-mutation endpoints. Each entry produces a typed handler
   * inside the generated useTableData hook. The cell renderer in TablePreview
   * calls the matching handler whenever the user toggles the control, the
   * UI is optimistically updated, and the request is sent in the background.
   */
  rowActions?: TableRowActionConfig[];
}

export interface TableRowActionConfig {
  /** Unique id for this action (also used as the handler name suffix). */
  id: string;
  /** Column key whose interaction triggers this action. */
  columnKey: string;
  /** Trigger type — controls which events the cell wires up. */
  trigger: "switch" | "checkbox" | "radio" | "dropdown" | "button" | "rating";
  /** HTTP method. */
  method: TableHttpMethod;
  /**
   * Path template appended to apiConfig.baseUrl. Tokens:
   *   :id    — row.id
   *   :{k}   — row[k]
   * Example: "/:id/toggle"
   */
  path: string;
  /**
   * Body template (string). Use {{value}} for the new value, {{rowId}} for
   * row.id, and {{row.field}} for any row property.
   * Example: '{ "active": {{value}} }'
   */
  body?: string;
  /** Extra query parameters. */
  query?: Record<string, string>;
  /** Optimistic UI: apply the change immediately and rollback on error. */
  optimistic?: boolean;
}

/** Sort descriptor used by both client- and server-side modes. */
export interface SortDescriptor {
  key: string;
  dir: "asc" | "desc";
}

/**
 * Sandboxed cell-click JS handler runner.
 *
 * The user can attach a small JS snippet to a column's `clickAction.code`
 * (when `clickAction.type === "js"`). Snippets execute with:
 *   - `row`     — the full row object (frozen).
 *   - `value`   — the cell's value.
 *   - `helpers` — a curated allowlist of helpers (`toast`, `copy`, `open`).
 *
 * Hardening:
 *   - Compiled with `new Function` as an **async** function so snippets may
 *     `await helpers.copy(value)` etc. The body runs in strict mode (the
 *     default for async functions), so we can't use `with` — instead we
 *     destructure the sandbox into local bindings as the very first line.
 *   - Common globals (`window`, `document`, `fetch`, `localStorage`, …) are
 *     shadowed with `undefined` parameters so naive `window.foo` access
 *     throws synchronously and is caught.
 *   - Errors are caught and surfaced via toast so a misbehaving snippet
 *     cannot crash the table.
 *
 * This is "safe enough" sandboxing for the builder preview / generated apps
 * the user controls — it is NOT a substitute for a real isolate when running
 * untrusted third-party code.
 */
import { toast } from "@/hooks/use-toast";

export interface CellJsHelpers {
  toast: (msg: string, variant?: "default" | "destructive") => void;
  copy: (text: string) => Promise<void>;
  open: (url: string, target?: "_self" | "_blank") => void;
  fetch: typeof fetch;
}

const SHADOWED_GLOBALS = [
  "window", "document", "globalThis", "self", "top", "parent",
  "fetch", "XMLHttpRequest", "WebSocket", "localStorage", "sessionStorage",
  "indexedDB", "navigator", "location", "history", "alert", "confirm", "prompt",
  "require",
];

function buildHelpers(): CellJsHelpers {
  return {
    toast: (msg, variant = "default") => {
      toast({ title: msg, variant });
    },
    copy: (text) => navigator.clipboard.writeText(String(text)),
    open: (url, target = "_self") => {
      if (target === "_blank") window.open(url, "_blank", "noopener,noreferrer");
      else window.location.href = url;
    },
    fetch: ((...args: Parameters<typeof fetch>) => window.fetch(...args)) as typeof fetch,
  };
}

/**
 * Compile + run a snippet. Returns `true` if it executed without throwing
 * synchronously. Async errors are caught and surfaced via toast.
 *
 * The snippet body is wrapped in an async function whose parameters destructure
 * the sandbox + shadow risky globals — this avoids the (illegal-in-strict-mode)
 * `with` statement while still preventing access to host globals. Users may
 * `await` and `return` freely.
 */
export function runCellJs(
  code: string,
  ctx: { row: Record<string, unknown>; value: unknown; el?: HTMLElement | null },
): boolean {
  if (!code.trim()) return false;
  const helpers = buildHelpers();
  // Freeze the row so snippets can't mutate the underlying table state.
  const safeRow = Object.freeze({ ...ctx.row });

  // Param order: row, value, helpers, el, console, ...shadowed globals.
  // Every shadowed name becomes a local `undefined` binding, masking the
  // real host global from inside the function body.
  const paramNames = ["row", "value", "helpers", "el", "console", ...SHADOWED_GLOBALS];
  const args: unknown[] = [
    safeRow,
    ctx.value,
    helpers,
    ctx.el ?? null,
    { log: console.log, warn: console.warn, error: console.error },
    ...SHADOWED_GLOBALS.map(() => undefined),
  ];

  // `eval` and `Function` are reserved/structural identifiers in strict mode
  // and cannot legally be used as parameter names. Shadow them inside the
  // function body instead so user code still can't reach the host versions.
  // `import` is a statement keyword — `new Function` bodies can never contain
  // a real `import` declaration, so it needs no shadowing.
  const wrappedBody = `var eval = undefined, Function = undefined;\n${code}\n`;

  let fn: (...a: unknown[]) => Promise<unknown>;
  try {
    const AsyncFn = Object.getPrototypeOf(async function () {}).constructor;
    // Async function body — supports `await` natively. Strict mode is implicit.
    fn = new AsyncFn(...paramNames, wrappedBody) as typeof fn;
  } catch (e) {
    toast({
      title: "Snippet syntax error",
      description: e instanceof Error ? e.message : "Unknown error",
      variant: "destructive",
    });
    return false;
  }

  try {
    const result = fn(...args);
    if (result && typeof (result as Promise<unknown>).then === "function") {
      (result as Promise<unknown>).catch((e) => {
        toast({
          title: "Cell handler runtime error",
          description: e instanceof Error ? e.message : "Unknown error",
          variant: "destructive",
        });
      });
    }
    return true;
  } catch (e) {
    toast({
      title: "Cell handler runtime error",
      description: e instanceof Error ? e.message : "Unknown error",
      variant: "destructive",
    });
    return false;
  }
}

/**
 * Mustache-style template renderer for the user-defined row dialog.
 *
 * Supports:
 *   {{row.field}}            → row[field] (HTML-escaped)
 *   {{{row.field}}}          → row[field] (raw — for trusted nested HTML)
 *   {{value}}                → cell value (HTML-escaped)
 *   {{#if row.field}}…{{/if}}        → conditional block
 *   {{#each row.tags}}…{{/each}}     → loops over array; inner uses {{this}}
 *
 * After interpolation the result is sanitized to remove <script> tags and
 * inline event handlers (on*=…) so a careless template can't introduce XSS
 * even if the row data is user-controlled. The result is meant to be used
 * with `dangerouslySetInnerHTML`.
 */

function escapeHtml(value: unknown): string {
  if (value == null) return "";
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function resolvePath(scope: Record<string, unknown>, path: string): unknown {
  const parts = path.split(".").map((p) => p.trim()).filter(Boolean);
  let current: unknown = scope;
  for (const part of parts) {
    if (current == null) return undefined;
    if (typeof current !== "object") return undefined;
    current = (current as Record<string, unknown>)[part];
  }
  return current;
}

function isTruthy(v: unknown): boolean {
  if (Array.isArray(v)) return v.length > 0;
  if (v && typeof v === "object") return Object.keys(v).length > 0;
  return Boolean(v);
}

/** Strip <script> blocks, inline `on*=` handlers, and `javascript:` URLs. */
function sanitize(html: string): string {
  return html
    .replace(/<script\b[\s\S]*?<\/script>/gi, "")
    .replace(/<style\b[\s\S]*?<\/style>/gi, "")
    .replace(/\son[a-z]+\s*=\s*"[^"]*"/gi, "")
    .replace(/\son[a-z]+\s*=\s*'[^']*'/gi, "")
    .replace(/\son[a-z]+\s*=\s*[^\s>]+/gi, "")
    .replace(/(href|src|action)\s*=\s*"\s*javascript:[^"]*"/gi, '$1="#"')
    .replace(/(href|src|action)\s*=\s*'\s*javascript:[^']*'/gi, "$1='#'");
}

interface Scope {
  row: Record<string, unknown>;
  value: unknown;
  this?: unknown;
}

function renderInternal(template: string, scope: Scope): string {
  // Each loops first.
  let out = template.replace(
    /\{\{#each\s+([\w.]+)\}\}([\s\S]*?)\{\{\/each\}\}/g,
    (_m, path: string, body: string) => {
      const list = resolvePath(scope as unknown as Record<string, unknown>, path);
      if (!Array.isArray(list)) return "";
      return list
        .map((item) => renderInternal(body, { ...scope, this: item }))
        .join("");
    },
  );

  // If blocks.
  out = out.replace(
    /\{\{#if\s+([\w.]+)\}\}([\s\S]*?)\{\{\/if\}\}/g,
    (_m, path: string, body: string) => {
      const v = resolvePath(scope as unknown as Record<string, unknown>, path);
      return isTruthy(v) ? renderInternal(body, scope) : "";
    },
  );

  // Triple-stache (raw).
  out = out.replace(/\{\{\{\s*([\w.]+)\s*\}\}\}/g, (_m, path: string) => {
    const v = resolvePath(scope as unknown as Record<string, unknown>, path);
    return v == null ? "" : String(v);
  });

  // Double-stache (escaped).
  out = out.replace(/\{\{\s*([\w.]+)\s*\}\}/g, (_m, path: string) => {
    const v = resolvePath(scope as unknown as Record<string, unknown>, path);
    return escapeHtml(v);
  });

  return out;
}

export function renderRowDialogTemplate(
  template: string,
  ctx: { row: Record<string, unknown>; value: unknown },
): string {
  const interpolated = renderInternal(template, { row: ctx.row, value: ctx.value });
  return sanitize(interpolated);
}

/** Render a plain-text mustache string (used for dialog title/description). */
export function renderRowDialogText(
  template: string,
  ctx: { row: Record<string, unknown>; value: unknown },
): string {
  const out = template.replace(/\{\{\s*([\w.]+)\s*\}\}/g, (_m, path: string) => {
    const v = resolvePath({ row: ctx.row, value: ctx.value }, path);
    return v == null ? "" : String(v);
  });
  return out;
}

