export type VariantJsonConfigBlock = {
  value: unknown;
  /** Uppercase section title (table: "Table config", "Sample data"). Omit for single-block form/kanban layout. */
  label?: string;
  /** Tailwind max-height class on ScrollArea (default: sectioned `max-h-[320px]`, single `max-h-[400px]`). */
  maxHeightClass?: string;
  /** Toast description after copy (defaults by label / generic). */
  copySuccessDescription?: string;
};

export type VariantJsonConfigPanelProps = {
  /** Controlled open state (optional). */
  open?: boolean;
  /** Subtitle in header, e.g. `6 columns · 5 rows` */
  titleMeta?: string;
  className?: string;
  defaultOpen?: boolean;
  blocks: VariantJsonConfigBlock[];
  onOpenChange?: (open: boolean) => void;
};

function stringifyJson(value: unknown): string {
  return JSON.stringify(value, null, 2);
}

/**
 * Collapsible JSON viewer shared by Form Builder preview, Table Preview,
 * Kanban Builder preview, and Kanban variants — same header rhythm, padding,
 * and copy affordances. Behaviour-preserving: still toggles + copies JSON.
 */
export function VariantJsonConfigPanel({
  blocks,
  titleMeta,
  className,
  open: openProp,
  defaultOpen = false,
  onOpenChange,
}: VariantJsonConfigPanelProps) {
  const contentId = useId();
  const [internalOpen, setInternalOpen] = useState(defaultOpen);
  const controlled = openProp !== undefined;
  const open = controlled ? openProp : internalOpen;

  const setOpen = useCallback(
    (next: boolean) => {
      if (!controlled) setInternalOpen(next);
      onOpenChange?.(next);
    },
    [controlled, onOpenChange],
  );

  const sectioned =
    blocks.length > 1 || blocks.some((b) => (b.label?.trim() ?? "").length > 0);

  const [copiedKey, setCopiedKey] = useState<string | null>(null);
  useEffect(() => {
    if (!copiedKey) return;
    const t = window.setTimeout(() => setCopiedKey(null), 2000);
    return () => window.clearTimeout(t);
  }, [copiedKey]);

  const copyBlock = async (block: VariantJsonConfigBlock, key: string) => {
    try {
      await navigator.clipboard.writeText(stringifyJson(block.value));
      setCopiedKey(key);
      toast({
        title: "Copied",
        description:
          block.copySuccessDescription ??
          (block.label
            ? `${block.label} copied to clipboard`
            : "JSON copied to clipboard"),
      });
    } catch {
      toast({
        title: "Copy failed",
        description: "Could not write to clipboard",
        variant: "destructive",
      });
    }
  };

  if (blocks.length === 0) return null;

  return (
    <Card className={cn("border-border", className)}>
      <Collapsible open={open} onOpenChange={setOpen}>
        <CollapsibleTrigger asChild>
          <CardHeader
            className="cursor-pointer px-4 py-3 transition-colors select-none hover:bg-muted/30"
            id={`${contentId}-trigger`}
            aria-controls={`${contentId}-content`}
          >
            <div className="flex items-center justify-between gap-2">
              <div className="flex min-w-0 flex-1 items-center gap-2">
                <FileJson className="h-4 w-4 shrink-0 text-primary" />
                <CardTitle className="shrink-0 text-sm">
                  JSON Configuration
                </CardTitle>
                {titleMeta ? (
                  <span className="truncate text-[10px] font-normal text-muted-foreground">
                    {titleMeta}
                  </span>
                ) : null}
              </div>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="h-7 w-7 shrink-0"
                aria-expanded={open}
                aria-label={open ? "Collapse JSON" : "Expand JSON"}
              >
                {open ? (
                  <ChevronUp className="h-4 w-4" />
                ) : (
                  <ChevronDown className="h-4 w-4" />
                )}
              </Button>
            </div>
          </CardHeader>
        </CollapsibleTrigger>
        <CollapsibleContent id={`${contentId}-content`}>
          <CardContent className="space-y-3 px-4 pb-4 pt-0">
            {sectioned
              ? blocks.map((block, i) => {
                  const key = `${i}-${block.label ?? "block"}`;
                  const maxH = block.maxHeightClass ?? "max-h-[320px]";
                  return (
                    <div key={key}>
                      <div className="mb-1.5 flex items-center justify-between gap-2">
                        <span className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
                          {block.label?.trim() || `Section ${i + 1}`}
                        </span>
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          className="h-6 gap-1 text-[10px]"
                          onClick={() => void copyBlock(block, key)}
                        >
                          {copiedKey === key ? (
                            <Check className="h-3 w-3 text-primary" />
                          ) : (
                            <Copy className="h-3 w-3" />
                          )}
                          {copiedKey === key ? "Copied" : "Copy"}
                        </Button>
                      </div>
                      <ScrollArea className={maxH}>
                        <pre className="overflow-x-auto rounded-lg border border-border bg-muted/50 p-3 font-mono text-[11px] leading-relaxed">
                          {stringifyJson(block.value)}
                        </pre>
                      </ScrollArea>
                    </div>
                  );
                })
              : blocks[0] && (
                  <div className="relative overflow-hidden rounded-lg border border-border bg-muted/50">
                    <Button
                      type="button"
                      size="sm"
                      variant="secondary"
                      className="absolute end-2 top-2 z-10 h-7 gap-1.5 px-2 text-xs shadow-sm"
                      onClick={() => void copyBlock(blocks[0], "single")}
                    >
                      {copiedKey === "single" ? (
                        <Check className="h-3.5 w-3.5 text-primary" />
                      ) : (
                        <Copy className="h-3.5 w-3.5" />
                      )}
                      {copiedKey === "single" ? "Copied" : "Copy"}
                    </Button>
                    <ScrollArea
                      className={blocks[0].maxHeightClass ?? "max-h-[400px]"}
                    >
                      <pre className="min-w-max p-3 pe-24 pb-3 font-mono text-xs leading-relaxed whitespace-pre">
                        {stringifyJson(blocks[0].value)}
                      </pre>
                    </ScrollArea>
                  </div>
                )}
          </CardContent>
        </CollapsibleContent>
      </Collapsible>
    </Card>
  );
}

/**
 * Default rich cell renderer for the table engine.
 *
 * This contains every built-in `col.type` visual (badge, progress, currency,
 * date, email, link, boolean, switch, radio, dropdown, rating, status-dot,
 * tags, avatar, avatar-image, actions, number, text). It used to live inline
 * inside `TablePreview.tsx` — extracting it makes the engine slimmer and lets
 * variants opt out per-column or per-table via `column.renderCell` /
 * `config.renderCell` (which already short-circuit this fallback).
 *
 * Resolution order at render time:
 *   column.renderCell  ->  config.renderCell  ->  defaultRichCellRenderer  ->  raw text
 */
import { MoreHorizontal, RefreshCw, Star } from "lucide-react";

import { cn } from "@/lib/utils";
import type { TableColumnConfig } from "./types";

import {
  Select,
  SelectItem,
  SelectValue,
  SelectContent,
  SelectTrigger,
} from "@/components/ui/select";
import {
  DropdownMenu,
  DropdownMenuItem,
  DropdownMenuContent,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Progress } from "@/components/ui/progress";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

export interface DefaultCellRowAction {
  id: string;
  title: string;
  onClick: () => void;
}

export interface DefaultCellRendererProps {
  val: unknown;
  inlineEdit: boolean;
  col: TableColumnConfig;
  onCellClick?: () => void;
  row: Record<string, unknown>;
  rowActionButtons?: DefaultCellRowAction[];
  density: "comfortable" | "compact" | "spacious";
  onUpdate: (rowId: string, key: string, value: unknown) => void;
}

function getInitials(name: string) {
  return String(name)
    .split(" ")
    .map((p) => p[0])
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

export function DefaultCellRenderer({
  col,
  row,
  val,
  density,
  onUpdate,
  inlineEdit,
  onCellClick,
  rowActionButtons,
}: DefaultCellRendererProps) {
  const sizeClass =
    density === "compact"
      ? "text-[11px]"
      : density === "spacious"
        ? "text-sm"
        : "text-xs";
  const underlineClass = col.underline
    ? "underline underline-offset-4 decoration-solid decoration-current"
    : "";
  const clickable = !!onCellClick;
  const interactiveClass = clickable
    ? "cursor-pointer hover:text-primary hover:decoration-primary transition-colors"
    : "";
  const handleClick = (e: React.MouseEvent) => {
    if (!clickable) return;
    e.stopPropagation();
    onCellClick?.();
  };

  switch (col.type) {
    case "badge":
      return (
        <Badge
          variant={
            (col.badgeVariants?.[String(val)] || "secondary") as
              | "default"
              | "secondary"
              | "outline"
              | "destructive"
          }
          className={cn(sizeClass, underlineClass, interactiveClass)}
          onClick={handleClick}
        >
          {String(val)}
        </Badge>
      );

    case "progress":
      return (
        <div className="flex items-center gap-2 min-w-[80px]">
          <Progress value={Number(val) || 0} className="h-1.5 flex-1" />
          <span
            className={cn(sizeClass, "text-muted-foreground w-9 tabular-nums")}
          >
            {Number(val) || 0}%
          </span>
        </div>
      );

    case "currency":
      return (
        <span
          className={cn(
            sizeClass,
            "font-medium tabular-nums",
            underlineClass,
            interactiveClass,
          )}
          onClick={handleClick}
        >
          {col.format || "$"}
          {Number(val).toLocaleString()}
        </span>
      );

    case "date":
      return (
        <span
          className={cn(
            sizeClass,
            "text-muted-foreground tabular-nums",
            underlineClass,
            interactiveClass,
          )}
          onClick={handleClick}
        >
          {String(val ?? "—")}
        </span>
      );

    case "email":
      return clickable ? (
        <button
          type="button"
          onClick={handleClick}
          className={cn(
            sizeClass,
            "text-primary hover:underline truncate block max-w-[180px] text-start",
            underlineClass,
          )}
        >
          {String(val ?? "—")}
        </button>
      ) : (
        <a
          href={`mailto:${val}`}
          data-noclick="true"
          onClick={(e) => e.stopPropagation()}
          className={cn(
            sizeClass,
            "text-primary hover:underline truncate block max-w-[180px]",
            underlineClass,
          )}
        >
          {String(val ?? "—")}
        </a>
      );

    case "link":
      return clickable ? (
        <button
          type="button"
          data-noclick="true"
          onClick={handleClick}
          className={cn(
            sizeClass,
            "text-primary hover:underline truncate block max-w-[220px] text-start",
            underlineClass,
          )}
        >
          {String(val)}
        </button>
      ) : (
        <a
          target="_blank"
          rel="noreferrer"
          href={String(val)}
          data-noclick="true"
          onClick={(e) => e.stopPropagation()}
          className={cn(
            sizeClass,
            "text-primary hover:underline",
            underlineClass,
          )}
        >
          {String(val)}
        </a>
      );

    case "boolean":
      return (
        <Badge
          variant={val ? "default" : "secondary"}
          className={cn(sizeClass)}
        >
          {val ? "Yes" : "No"}
        </Badge>
      );

    case "switch":
      return (
        <Switch
          data-noclick="true"
          checked={Boolean(val)}
          onCheckedChange={(v) => onUpdate(row.id as string, col.key, v)}
          onClick={(e) => e.stopPropagation()}
          className="scale-90"
          disabled={!inlineEdit}
        />
      );

    case "radio":
      return (
        <RadioGroup
          data-noclick="true"
          value={String(val ?? "")}
          onValueChange={(v) => onUpdate(row.id as string, col.key, v)}
          className="flex gap-2"
          onClick={(e) => e.stopPropagation()}
          disabled={!inlineEdit}
        >
          {(col.options || []).map((opt) => (
            <label
              key={opt.value}
              className="flex items-center gap-1 text-xs cursor-pointer"
            >
              <RadioGroupItem value={opt.value} className="h-3 w-3" />
              <span>{opt.label}</span>
            </label>
          ))}
        </RadioGroup>
      );

    case "dropdown":
      if (!inlineEdit) {
        return (
          <Badge variant="outline" className={cn(sizeClass)}>
            {String(val ?? "—")}
          </Badge>
        );
      }
      return (
        <Select
          value={String(val ?? "")}
          onValueChange={(v) => onUpdate(row.id as string, col.key, v)}
        >
          <SelectTrigger
            data-noclick="true"
            className="h-7 text-xs w-32 border-border/40"
            onClick={(e) => e.stopPropagation()}
          >
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            {(col.options || []).map((opt) => (
              <SelectItem key={opt.value} value={opt.value} className="text-xs">
                {opt.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      );

    case "rating": {
      const n = Number(val) || 0;
      return (
        <div className="flex items-center gap-0.5">
          {Array.from({ length: 5 }).map((_, i) => (
            <Star
              key={i}
              className={cn(
                "h-3.5 w-3.5",
                i < n
                  ? "fill-amber-400 text-amber-400"
                  : "text-muted-foreground/30",
              )}
            />
          ))}
        </div>
      );
    }

    case "status-dot": {
      const opt = col.options?.find((o) => o.value === val);
      const color = opt?.color || "hsl(var(--muted-foreground))";
      return (
        <div className="flex items-center gap-2">
          <span
            className="h-2 w-2 rounded-full shrink-0"
            style={{ backgroundColor: color }}
          />
          <span className={cn(sizeClass, "font-medium")}>
            {opt?.label || String(val ?? "—")}
          </span>
        </div>
      );
    }

    case "tags": {
      const tags = Array.isArray(val) ? val : [];
      return (
        <div className="flex flex-wrap gap-1">
          {tags.map((t, i) => (
            <Badge key={i} variant="outline" className="text-[10px]">
              {String(t)}
            </Badge>
          ))}
        </div>
      );
    }

    case "avatar":
      return (
        <div className="flex items-center gap-2">
          <Avatar className="h-7 w-7">
            <AvatarFallback className="text-[10px] bg-primary/10 text-primary">
              {getInitials(String(val))}
            </AvatarFallback>
          </Avatar>
          <span className={cn(sizeClass, "font-medium truncate")}>
            {String(val ?? "—")}
          </span>
        </div>
      );

    case "avatar-image":
      return (
        <div className="flex items-center gap-2">
          <Avatar className="h-7 w-7">
            <AvatarImage src={String(row.avatarUrl || "")} />
            <AvatarFallback className="text-[10px] bg-primary/10 text-primary">
              {getInitials(String(val))}
            </AvatarFallback>
          </Avatar>
          <span className={cn(sizeClass, "font-medium truncate")}>
            {String(val ?? "—")}
          </span>
        </div>
      );

    case "actions":
      return (
        <div
          data-noclick="true"
          className="flex items-center justify-end gap-1"
          onClick={(e) => e.stopPropagation()}
          onPointerDown={(e) => e.stopPropagation()}
        >
          {rowActionButtons?.map((b) => (
            <Button
              key={b.id}
              variant="ghost"
              size="icon"
              className="h-7 w-7"
              title={b.title}
              onClick={(e) => {
                e.stopPropagation();
                b.onClick();
              }}
            >
              <RefreshCw className="h-3.5 w-3.5" />
            </Button>
          ))}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7"
                onClick={(e) => e.stopPropagation()}
              >
                <MoreHorizontal className="h-3.5 w-3.5" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent
              align="end"
              onClick={(e) => e.stopPropagation()}
            >
              <DropdownMenuItem
                className="text-xs"
                onClick={(e) => e.stopPropagation()}
              >
                Edit
              </DropdownMenuItem>
              <DropdownMenuItem
                className="text-xs"
                onClick={(e) => e.stopPropagation()}
              >
                Duplicate
              </DropdownMenuItem>
              <DropdownMenuSeparator />
              <DropdownMenuItem
                className="text-xs text-destructive"
                onClick={(e) => e.stopPropagation()}
              >
                Delete
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      );

    case "number":
      return (
        <span
          className={cn(
            sizeClass,
            "tabular-nums",
            underlineClass,
            interactiveClass,
          )}
          onClick={handleClick}
        >
          {val == null ? "—" : Number(val).toLocaleString()}
        </span>
      );

    default:
      return (
        <span
          className={cn(
            sizeClass,
            "truncate block",
            underlineClass,
            interactiveClass,
          )}
          onClick={handleClick}
        >
          {String(val ?? "—")}
        </span>
      );
  }
}

/**
 * Default expandable-row body. Renders one of seven preset layouts based on
 * `config.expandableLayout`. Engine fallback when the variant does not supply
 * a typed JSX `renderExpandedRow` function.
 *
 * Resolution order (built into TablePreview):
 *   config.renderExpandedRow(ctx)   →   <DefaultExpandedRow layout={...} />
 *
 * This component is purposely standalone so user-supplied renderers can
 * compose with it, e.g.:
 *
 *   renderExpandedRow: (ctx) => (
 *     <>
 *       <DefaultExpandedRow {...ctx} layout="card" />
 *       <MyExtraChart row={ctx.row} />
 *     </>
 *   )
 */
import { CheckCircle2, Circle } from "lucide-react";

import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

import { cn } from "@/lib/utils";
import type { TableRow, ExpandableLayout, TableColumnConfig } from "./types";

export interface DefaultExpandedRowProps<T extends TableRow = TableRow> {
  row: T;
  layout?: ExpandableLayout;
  /** Reserved for future layouts that need column metadata. Currently unused. */
  columns?: TableColumnConfig[];
  rowIndex?: number;
}

interface Milestone {
  date: string;
  label: string;
  done: boolean;
}

const EXCLUDED_KEYS = new Set<string>(["id", "milestones", "assets"]);
const KPI_KEYS = ["calls", "demos", "win", "deals", "revenue", "quota"];

function getEntries(row: TableRow): Array<[string, unknown]> {
  return Object.entries(row).filter(([k]) => !EXCLUDED_KEYS.has(k));
}

export function DefaultExpandedRow<T extends TableRow = TableRow>({
  row,
  layout = "details",
}: DefaultExpandedRowProps<T>) {
  const entries = getEntries(row);

  switch (layout) {
    case "card":
      return (
        <div className="px-4 py-4 bg-gradient-to-br from-muted/40 to-muted/20">
          <Card className="border-border shadow-sm">
            <CardHeader className="pb-2 pt-3 px-4">
              <CardTitle className="text-sm">Full Details</CardTitle>
            </CardHeader>
            <CardContent className="px-4 pb-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                {entries.map(([k, v]) => (
                  <div
                    key={k}
                    className="space-y-0.5 p-2.5 rounded-md bg-muted/30 border border-border/40"
                  >
                    <div className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold">
                      {k}
                    </div>
                    <div className="text-xs font-medium truncate">
                      {String(v)}
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </div>
      );

    case "grid":
      return (
        <div className="px-4 py-4 bg-muted/20">
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-2">
            {entries.map(([k, v]) => (
              <div
                key={k}
                className="flex flex-col items-center justify-center text-center p-3 rounded-lg bg-background border border-border/60"
              >
                <div className="text-[9px] uppercase tracking-wider text-muted-foreground font-semibold mb-1">
                  {k}
                </div>
                <div className="text-sm font-bold tabular-nums truncate w-full">
                  {String(v)}
                </div>
              </div>
            ))}
          </div>
        </div>
      );

    case "tabs":
      return (
        <div className="px-4 py-3 bg-muted/20">
          <Tabs defaultValue="details" className="w-full">
            <TabsList className="h-8">
              <TabsTrigger value="details" className="text-xs h-6 px-3">
                Details
              </TabsTrigger>
              <TabsTrigger value="raw" className="text-xs h-6 px-3">
                Raw JSON
              </TabsTrigger>
            </TabsList>
            <TabsContent value="details" className="mt-2">
              <div className="grid sm:grid-cols-2 gap-x-6 gap-y-1.5 px-2">
                {entries.map(([k, v]) => (
                  <div key={k} className="flex justify-between text-xs">
                    <span className="text-muted-foreground capitalize">
                      {k}:
                    </span>
                    <span className="font-medium truncate ms-2">
                      {String(v)}
                    </span>
                  </div>
                ))}
              </div>
            </TabsContent>
            <TabsContent value="raw" className="mt-2">
              <pre className="text-[10px] bg-background border border-border rounded p-2 overflow-x-auto">
                {JSON.stringify(row, null, 2)}
              </pre>
            </TabsContent>
          </Tabs>
        </div>
      );

    case "timeline": {
      const milestones = (row.milestones as Milestone[] | undefined) ?? [];
      return (
        <div className="px-6 py-4 bg-muted/20">
          <p className="text-xs font-semibold text-foreground mb-3">
            Milestones
          </p>
          <div className="relative ms-2">
            <div className="absolute start-1.5 top-1 bottom-1 w-px bg-border" />
            <div className="space-y-3">
              {milestones.length === 0 ? (
                <p className="text-xs text-muted-foreground">
                  No milestones available.
                </p>
              ) : (
                milestones.map((m, i) => (
                  <div key={i} className="relative flex items-start gap-3 ps-5">
                    <div className="absolute start-0 top-0.5">
                      {m.done ? (
                        <CheckCircle2 className="h-3 w-3 text-primary" />
                      ) : (
                        <Circle className="h-3 w-3 text-muted-foreground" />
                      )}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-xs font-medium">{m.label}</div>
                      <div className="text-[10px] text-muted-foreground">
                        {m.date}
                      </div>
                    </div>
                    {m.done && (
                      <Badge variant="secondary" className="text-[9px]">
                        Done
                      </Badge>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      );
    }

    case "gallery": {
      const assets = (row.assets as string[] | undefined) ?? [];
      return (
        <div className="px-4 py-4 bg-muted/20">
          <p className="text-xs font-semibold text-foreground mb-3">
            Asset Preview ({assets.length})
          </p>
          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
            {assets.map((cls, i) => (
              <div
                key={i}
                className={cn(
                  "aspect-square rounded-lg flex items-center justify-center text-white text-xs font-bold shadow-sm",
                  cls,
                )}
              >
                {i + 1}
              </div>
            ))}
          </div>
        </div>
      );
    }

    case "stats": {
      const kpis = KPI_KEYS.filter((k) => row[k] !== undefined).map((k) => ({
        key: k,
        value: row[k],
      }));
      return (
        <div className="px-4 py-4 bg-muted/20">
          <p className="text-xs font-semibold text-foreground mb-3">
            Performance Breakdown
          </p>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-2">
            {kpis.length === 0 ? (
              <p className="text-xs text-muted-foreground col-span-full">
                No KPI fields available.
              </p>
            ) : (
              kpis.map(({ key, value }) => (
                <div
                  key={key}
                  className="p-3 rounded-lg bg-background border border-border/60"
                >
                  <div className="text-[9px] uppercase tracking-wider text-muted-foreground font-semibold">
                    {key}
                  </div>
                  <div className="text-lg font-bold tabular-nums mt-0.5">
                    {String(value)}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      );
    }

    case "details":
    default:
      return (
        <div className="px-4 py-3">
          <p className="text-xs font-semibold text-foreground mb-1">
            Row Details
          </p>
          <div className="grid sm:grid-cols-2 gap-x-6 gap-y-1">
            {entries.map(([k, v]) => (
              <div key={k} className="flex justify-between text-xs">
                <span className="text-muted-foreground capitalize">{k}:</span>
                <span className="font-medium truncate ms-2">{String(v)}</span>
              </div>
            ))}
          </div>
        </div>
      );
  }
}

/**
 * Default pagination bar — the single built-in fallback rendered when
 * `config.enablePagination` is true and the user did NOT supply
 * `config.renderPagination`.
 *
 * Exported so user-supplied `renderPagination` functions can compose with
 * it, and so the generator can wire it into exported variants.
 *
 * Resolution order at render time (built into the engine):
 *   config.renderPagination → <DefaultPaginationBar />
 */
import { Button } from "@/components/ui/button";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight,
} from "lucide-react";
import type { TableBuilderConfig, PaginationRenderContext } from "./types";

export interface DefaultPaginationBarProps extends PaginationRenderContext {
  config: TableBuilderConfig;
}

export function DefaultPaginationBar({
  page, setPage, totalPages, pageSize, setPageSize, totalRows, config,
}: DefaultPaginationBarProps) {
  const layout = config.paginationLayout || "full";
  const showInfo = config.showPageInfo !== false;
  const showFirstLast = config.showFirstLastButtons !== false;
  const showSizeSelector = config.showPageSizeSelector === true;
  const sizeOptions = config.pageSizeOptions?.length ? config.pageSizeOptions : [5, 10, 20, 50];

  const info = showInfo && (
    <p className="text-xs text-muted-foreground">
      Showing {totalRows > 0 ? page * pageSize + 1 : 0}–{Math.min((page + 1) * pageSize, totalRows)} of {totalRows}
    </p>
  );

  const sizer = showSizeSelector && (
    <div className="flex items-center gap-1.5">
      <span className="text-xs text-muted-foreground hidden sm:inline">Rows:</span>
      <Select value={String(pageSize)} onValueChange={v => { setPageSize(Number(v)); setPage(0); }}>
        <SelectTrigger className="h-7 text-xs w-[70px]"><SelectValue /></SelectTrigger>
        <SelectContent>
          {sizeOptions.map(n => <SelectItem key={n} value={String(n)} className="text-xs">{n}</SelectItem>)}
        </SelectContent>
      </Select>
    </div>
  );

  const wrapClass = "flex items-center justify-between gap-2 px-4 py-3 border-t border-border flex-wrap";

  if (layout === "infoOnly") {
    return <div className={wrapClass}>{info}{sizer}</div>;
  }

  if (layout === "minimal") {
    return (
      <div className={wrapClass}>
        {info}
        <div className="flex items-center gap-2">
          {sizer}
          <Button variant="outline" size="sm" className="h-7 text-xs gap-1" disabled={page === 0} onClick={() => setPage(p => p - 1)}>
            <ChevronLeft className="h-3 w-3 rtl:rotate-180" /> Prev
          </Button>
          <Button variant="outline" size="sm" className="h-7 text-xs gap-1" disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>
            Next <ChevronRight className="h-3 w-3 rtl:rotate-180" />
          </Button>
        </div>
      </div>
    );
  }

  if (layout === "numbered") {
    const pages: (number | "...")[] = [];
    const maxBtns = 5;
    if (totalPages <= maxBtns) for (let i = 0; i < totalPages; i++) pages.push(i);
    else {
      pages.push(0);
      const start = Math.max(1, page - 1);
      const end = Math.min(totalPages - 2, page + 1);
      if (start > 1) pages.push("...");
      for (let i = start; i <= end; i++) pages.push(i);
      if (end < totalPages - 2) pages.push("...");
      pages.push(totalPages - 1);
    }
    return (
      <div className={wrapClass}>
        {info}
        <div className="flex items-center gap-1.5 flex-wrap">
          {sizer}
          <div className="flex items-center gap-1">
            <Button variant="outline" size="icon" className="h-7 w-7" disabled={page === 0} onClick={() => setPage(p => p - 1)}>
              <ChevronLeft className="h-3.5 w-3.5 rtl:rotate-180" />
            </Button>
            {pages.map((p, i) =>
              p === "..." ? (
                <span key={`e-${i}`} className="px-1.5 text-xs text-muted-foreground">…</span>
              ) : (
                <Button key={p} variant={p === page ? "default" : "outline"} size="icon" className="h-7 w-7 text-xs tabular-nums" onClick={() => setPage(p)}>
                  {p + 1}
                </Button>
              ),
            )}
            <Button variant="outline" size="icon" className="h-7 w-7" disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>
              <ChevronRight className="h-3.5 w-3.5 rtl:rotate-180" />
            </Button>
          </div>
        </div>
      </div>
    );
  }

  if (layout === "compact") {
    return (
      <div className={wrapClass}>
        {info}
        <div className="flex items-center gap-2">
          {sizer}
          <span className="text-xs tabular-nums">{page + 1}/{totalPages}</span>
          <div className="flex">
            <Button variant="outline" size="icon" className="h-7 w-7 rounded-e-none" disabled={page === 0} onClick={() => setPage(p => p - 1)}>
              <ChevronLeft className="h-3.5 w-3.5 rtl:rotate-180" />
            </Button>
            <Button variant="outline" size="icon" className="h-7 w-7 rounded-s-none -ms-px" disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>
              <ChevronRight className="h-3.5 w-3.5 rtl:rotate-180" />
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // FULL (default)
  return (
    <div className={wrapClass}>
      <div className="flex items-center gap-3 flex-wrap">{info}{sizer}</div>
      <div className="flex items-center gap-1">
        {showFirstLast && (
          <Button variant="outline" size="icon" className="h-7 w-7" disabled={page === 0} onClick={() => setPage(0)}>
            <ChevronsLeft className="h-3.5 w-3.5 rtl:rotate-180" />
          </Button>
        )}
        <Button variant="outline" size="icon" className="h-7 w-7" disabled={page === 0} onClick={() => setPage(p => p - 1)}>
          <ChevronLeft className="h-3.5 w-3.5 rtl:rotate-180" />
        </Button>
        <span className="text-xs px-2 tabular-nums">{page + 1} / {totalPages}</span>
        <Button variant="outline" size="icon" className="h-7 w-7" disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>
          <ChevronRight className="h-3.5 w-3.5 rtl:rotate-180" />
        </Button>
        {showFirstLast && (
          <Button variant="outline" size="icon" className="h-7 w-7" disabled={page >= totalPages - 1} onClick={() => setPage(totalPages - 1)}>
            <ChevronsRight className="h-3.5 w-3.5 rtl:rotate-180" />
          </Button>
        )}
      </div>
    </div>
  );
}

/**
 * Default row-detail dialog body — the single built-in fallback rendered when
 * `rowClickAction.type === "dialog"` and neither `renderDialog` nor
 * `dialogTemplate` is supplied.
 *
 * Resolution order (built into the engine):
 *   rowClickAction.renderDialog → rowClickAction.dialogTemplate → <DefaultRowDialogBody />
 */
import type { TableRow } from "./types";

export function DefaultRowDialogBody({ row }: { row: TableRow }) {
  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
      {Object.entries(row).map(([k, v]) => (
        <div key={k} className="p-2.5 rounded-md bg-muted/40 border border-border/50">
          <div className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold">{k}</div>
          <div className="text-xs font-medium break-words mt-0.5">
            {typeof v === "object" ? JSON.stringify(v) : String(v ?? "—")}
          </div>
        </div>
      ))}
    </div>
  );
}

/**
 * Network layer for row-action API calls. Kept dependency-free (no React, no
 * UI imports) so the same helpers can be reused from tests, server-side
 * code, or alternative renderers.
 *
 * All token interpolation (`:id`, `:{field}`, `{{value}}`, `{{rowId}}`,
 * `{{row.field}}`) lives here — components and hooks call the high-level
 * `runRowActionRequest` / `runRowActionButton` functions.
 */
import type { TableApiConfig, TableRowActionConfig } from "./types";

function interpolatePath(path: string, row: Record<string, unknown>): string {
  return path
    .replace(/:id\b/g, String(row.id))
    .replace(/:(\w+)/g, (_, k: string) => String(row[k] ?? ""));
}

function buildQuery(query?: Record<string, string>): string {
  if (!query || Object.keys(query).length === 0) return "";
  return "?" + new URLSearchParams(query).toString();
}

function interpolateBody(template: string, row: Record<string, unknown>, value: unknown): string {
  return template
    .replace(/{{value}}/g, JSON.stringify(value))
    .replace(/{{rowId}}/g, JSON.stringify(row.id))
    .replace(/{{row\.(\w+)}}/g, (_, k: string) => JSON.stringify(row[k]));
}

export interface RowActionResult {
  ok: boolean;
  status: number;
  error?: Error;
  /** Method + interpolated path — handy for toast messages. */
  label: string;
}

/**
 * Fire the configured request for an interactive cell change
 * (switch / dropdown / radio / rating). Returns a result object — callers
 * decide whether to rollback / surface a toast.
 */
export async function runRowActionRequest(
  action: TableRowActionConfig,
  api: TableApiConfig,
  row: Record<string, unknown>,
  value: unknown,
): Promise<RowActionResult> {
  const path = interpolatePath(action.path, row);
  const url = `${api.baseUrl}${path}${buildQuery(action.query)}`;
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    ...(api.headers ?? {}),
  };
  let body: string | undefined;
  if (action.method !== "GET" && action.method !== "DELETE") {
    body = action.body
      ? interpolateBody(action.body, row, value)
      : JSON.stringify({ [action.columnKey]: value });
  }
  const label = `${action.method} ${path}`;
  try {
    const res = await fetch(url, { method: action.method, headers, body });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return { ok: true, status: res.status, label };
  } catch (e) {
    return {
      ok: false,
      status: 0,
      error: e instanceof Error ? e : new Error("network error"),
      label,
    };
  }
}

/**
 * Fire a button-trigger row action (action column buttons). Same semantics
 * as `runRowActionRequest`, but no `value` is involved — body interpolation
 * skips `{{value}}` and defaults to `{ id: row.id }`.
 */
export async function runRowActionButton(
  action: TableRowActionConfig,
  api: TableApiConfig,
  row: Record<string, unknown>,
): Promise<RowActionResult> {
  const path = interpolatePath(action.path, row);
  const url = `${api.baseUrl}${path}${buildQuery(action.query)}`;
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    ...(api.headers ?? {}),
  };
  let body: string | undefined;
  if (action.method !== "GET" && action.method !== "DELETE") {
    body = action.body
      ? interpolateBody(action.body, row, null)
      : JSON.stringify({ id: row.id });
  }
  const label = `${action.method} ${path}`;
  try {
    const res = await fetch(url, { method: action.method, headers, body });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return { ok: true, status: res.status, label };
  } catch (e) {
    return {
      ok: false,
      status: 0,
      error: e instanceof Error ? e : new Error("network error"),
      label,
    };
  }
}

/**
 * Encapsulates every API-bound piece of row-action logic the engine needs:
 *
 *   • `wrappedCellUpdate(rowId, key, value)` — optimistic local update +
 *     user `onCellInteract` dispatch + matching `apiConfig.rowActions` fetch
 *     with rollback on failure.
 *   • `getRowActionButtons(row, col)` — builds the click handlers for any
 *     `trigger:"button"` row actions targeting an `actions` column.
 *
 * Network calls themselves live in `./tableServices` — this hook just glues
 * them to React state + the user's callback.
 */
import { useCallback } from "react";

import { toast } from "@/hooks/use-toast";
import { runRowActionRequest, runRowActionButton } from "./tableServices";
import type { TableBuilderConfig, TableColumnConfig, TableRow } from "./types";

import type { DefaultCellRowAction } from "./defaultCellRenderer";

export interface UseRowApiActionsArgs {
  rows: TableRow[];
  /** Optional user-supplied dispatcher (typed per-column handlers). */
  onCellInteract?: (
    row: TableRow,
    key: string,
    oldValue: unknown,
    newValue: unknown,
  ) => Promise<void> | void;
  config: TableBuilderConfig;
  /** Optimistic local mutation used by both the user dispatch + rollback. */
  applyLocalUpdate: (rowId: string, key: string, value: unknown) => void;
}

export interface UseRowApiActionsReturn {
  getRowActionButtons: (
    row: Record<string, unknown>,
    col: TableColumnConfig,
  ) => DefaultCellRowAction[];
  wrappedCellUpdate: (rowId: string, key: string, value: unknown) => void;
}

export function useRowApiActions({
  config,
  rows,
  applyLocalUpdate,
  onCellInteract,
}: UseRowApiActionsArgs): UseRowApiActionsReturn {
  const wrappedCellUpdate = useCallback(
    (rowId: string, key: string, value: unknown) => {
      const prev = rows.find((r) => r.id === rowId);
      const prevValue = prev ? prev[key] : undefined;
      applyLocalUpdate(rowId, key, value);

      // ── user-supplied dispatcher (errors surfaced via toast; never rollback) ──
      if (onCellInteract && prev && prevValue !== value) {
        try {
          const result = onCellInteract(prev, key, prevValue, value);
          if (result && typeof (result as Promise<void>).catch === "function") {
            (result as Promise<void>).catch((e: unknown) => {
              toast({
                title: "Interaction handler failed",
                description: e instanceof Error ? e.message : "Unknown error",
                variant: "destructive",
              });
            });
          }
        } catch (e) {
          toast({
            title: "Interaction handler failed",
            description: e instanceof Error ? e.message : "Unknown error",
            variant: "destructive",
          });
        }
      }

      // ── apiConfig.rowActions matching this column key ──
      const action = config.apiConfig?.rowActions?.find(
        (a) => a.columnKey === key && a.trigger !== "button",
      );
      const api = config.apiConfig;
      if (!action || !api?.baseUrl || !prev) return;

      void runRowActionRequest(action, api, prev, value).then((result) => {
        if (!result.ok) {
          if (action.optimistic !== false)
            applyLocalUpdate(rowId, key, prevValue);
          toast({
            title: "Update failed",
            description: `${result.label} — ${result.error?.message ?? "network error"}`,
            variant: "destructive",
          });
        }
      });
    },
    [config.apiConfig, applyLocalUpdate, rows, onCellInteract],
  );

  const getRowActionButtons = useCallback(
    (row: Record<string, unknown>, col: TableColumnConfig): DefaultCellRowAction[] => {
      if (col.type !== "actions") return [];
      const api = config.apiConfig;
      const actions =
        api?.rowActions?.filter(
          (a) => a.trigger === "button" && a.columnKey === col.key,
        ) ?? [];
      if (actions.length === 0 || !api?.baseUrl) return [];
      return actions.map((action) => ({
        id: action.id,
        title: `${action.method} ${action.path}`,
        onClick: () => {
          void runRowActionButton(action, api, row).then((result) => {
            if (result.ok)
              toast({ title: "Action complete", description: result.label });
            else
              toast({
                title: "Action failed",
                description: `${result.label} — ${result.error?.message ?? "network error"}`,
                variant: "destructive",
              });
          });
        },
      }));
    },
    [config.apiConfig],
  );

  return { wrappedCellUpdate, getRowActionButtons };
}

/**
 * Single source of truth for wiring per-column renderers onto a table config.
 *
 * Resolution order applied at render time by the engine:
 *   column.renderCell  →  config.renderCell  →  built-in default
 *
 * O(n) single pass, no shallow-clone churn when a column has no override.
 */
import type { CellRenderer, TableColumnConfig } from "./types";

/** Map keyed by column id. */
export type CellRendererMap = Readonly<Record<string, CellRenderer | undefined>>;

export function attachCellRenderers(
  columns: readonly TableColumnConfig[],
  renderers: CellRendererMap,
): TableColumnConfig[] {
  const out: TableColumnConfig[] = new Array(columns.length);

  for (let i = 0; i < columns.length; i++) {
    const col = columns[i];
    const renderer = renderers[col.id];
    out[i] = renderer ? { ...col, renderCell: renderer } : col;
  }

  return out;
}

"use client";

/**
 * Custom Pointer DnD — Context Provider (shared library).
 *
 * Promoted from `src/components/kanban/dnd` so it can power any builder
 * (kanban, table rows, page-builder canvas, column reordering, …).
 *
 * Improvements over the kanban-only version:
 *   - **Axis-aware autoscroll.** A zone may declare `axis: "x"|"y"|"both"`.
 *     The provider scrolls the nearest scrollable ancestor on the matching
 *     axis when the pointer hugs an edge.
 *   - **Axis-aware index resolver.** When `axis: "x"` we compare X midpoints
 *     instead of Y, so horizontal lists (kanban columns, table column reorder)
 *     compute the correct insertion index.
 *   - Same single-render-per-slot-change flicker-killer as before.
 *   - Same Escape-to-cancel and pointer-event coverage.
 */
import {
  useRef,
  useMemo,
  useState,
  useEffect,
  useContext,
  useCallback,
  createContext,
  type ReactNode,
} from "react";
import { createPortal } from "react-dom";

import type {
  HoverState,
  DragSnapshot,
  DndContextValue,
  ZoneRegistration,
} from "./types";

const DndCtx = createContext<DndContextValue | null>(null);

const AUTOSCROLL_EDGE = 56;
const AUTOSCROLL_MAX_SPEED = 18;

function findScrollableAncestor(
  el: HTMLElement | null,
  axis: "x" | "y" | "both",
): HTMLElement | Window {
  let node: HTMLElement | null = el;
  while (node && node !== document.body) {
    const style = window.getComputedStyle(node);
    const overflowY = style.overflowY;
    const overflowX = style.overflowX;
    const scrollableY = (overflowY === "auto" || overflowY === "scroll" || overflowY === "overlay") && node.scrollHeight > node.clientHeight;
    const scrollableX = (overflowX === "auto" || overflowX === "scroll" || overflowX === "overlay") && node.scrollWidth > node.clientWidth;
    if (axis === "y" && scrollableY) return node;
    if (axis === "x" && scrollableX) return node;
    if (axis === "both" && (scrollableX || scrollableY)) return node;
    node = node.parentElement;
  }
  return window;
}

function getScrollRect(target: HTMLElement | Window): DOMRect {
  if (target === window) {
    return new DOMRect(0, 0, window.innerWidth, window.innerHeight);
  }
  return (target as HTMLElement).getBoundingClientRect();
}

function scrollBy(target: HTMLElement | Window, dx: number, dy: number) {
  if (target === window) window.scrollBy(dx, dy);
  else {
    (target as HTMLElement).scrollTop += dy;
    (target as HTMLElement).scrollLeft += dx;
  }
}

function getDragCenter(snap: DragSnapshot) {
  return {
    x: snap.clientX - snap.offsetX + snap.width / 2,
    y: snap.clientY - snap.offsetY + snap.height / 2,
  };
}

function isPointInsideRect(x: number, y: number, rect: DOMRect) {
  return x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom;
}

function isPointInsideSourceBounds(x: number, y: number, snap: DragSnapshot) {
  return snap.sourceLeft != null && snap.sourceRight != null && snap.sourceTop != null && snap.sourceBottom != null
    && x >= snap.sourceLeft
    && x <= snap.sourceRight
    && y >= snap.sourceTop
    && y <= snap.sourceBottom;
}

/**
 * Returns the index of a sibling item (excluding the dragged one) whose
 * bounding rect contains the given point, or null if the point is in a
 * gap / outside any sibling.
 */
function findSiblingIndexAt(
  zoneEl: HTMLElement,
  x: number,
  y: number,
): { visibleIndex: number; rect: DOMRect } | null {
  const items = zoneEl.querySelectorAll<HTMLElement>('[data-dnd-item="true"]');
  let visibleIndex = 0;
  for (let i = 0; i < items.length; i += 1) {
    const el = items[i];
    if (el.dataset.dragging === "true") continue;
    const rect = el.getBoundingClientRect();
    if (x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom) {
      return { visibleIndex, rect };
    }
    visibleIndex += 1;
  }
  return null;
}

/**
 * Compute the insertion index inside `zoneEl` based on pointer position.
 * `axis === "x"` → compare X midpoints. Otherwise → Y midpoints.
 * Excludes the currently-dragging item via `data-dragging="true"`.
 * For `axis === "x"` in RTL containers, the comparison is inverted so the
 * computed index matches the visual order (rightmost item = index 0 in RTL).
 */
function resolveDropIndex(
  zoneEl: HTMLElement,
  clientX: number,
  clientY: number,
  axis: "x" | "y" | "grid",
): number {
  const items = zoneEl.querySelectorAll<HTMLElement>('[data-dnd-item="true"]');
  const isRtl = (axis === "x" || axis === "grid") && window.getComputedStyle(zoneEl).direction === "rtl";
  let count = 0;

  if (axis === "grid") {
    // Group items into visual rows by Y midpoint, then resolve by X within row.
    const visible: { el: HTMLElement; rect: DOMRect }[] = [];
    for (let i = 0; i < items.length; i += 1) {
      const el = items[i];
      if (el.dataset.dragging === "true") continue;
      visible.push({ el, rect: el.getBoundingClientRect() });
    }
    if (visible.length === 0) return 0;

    const style = window.getComputedStyle(zoneEl);
    const columns = style.display.includes("grid")
      ? style.gridTemplateColumns.split(" ").filter(Boolean).length
      : 0;
    if (columns > 1) {
      const zoneRect = zoneEl.getBoundingClientRect();
      const columnGap = Number.parseFloat(style.columnGap) || 0;
      const rowGap = Number.parseFloat(style.rowGap) || 0;
      const cellWidth = (zoneRect.width - columnGap * (columns - 1)) / columns;
      const rowHeight = Math.max(...visible.map((item) => item.rect.height));
      const xInZone = Math.max(0, Math.min(clientX - zoneRect.left, zoneRect.width - 1));
      const yInZone = Math.max(0, clientY - zoneRect.top);
      const trackWidth = cellWidth + columnGap;
      const rowStep = rowHeight + rowGap;
      const visualCol = Math.max(0, Math.min(columns - 1, Math.floor(xInZone / trackWidth)));
      const col = isRtl ? columns - 1 - visualCol : visualCol;
      const row = Math.max(0, Math.floor(yInZone / rowStep));
      const rawIndex = row * columns + col;
      if (rawIndex >= visible.length) return visible.length;
      const cellStart = visualCol * trackWidth;
      const localX = xInZone - cellStart;
      const afterCellMidpoint = isRtl ? localX < cellWidth / 2 : localX > cellWidth / 2;
      return Math.max(0, Math.min(visible.length, rawIndex + (afterCellMidpoint ? 1 : 0)));
    }

    // Find the row the pointer is in (or before).
    for (let i = 0; i < visible.length; i += 1) {
      const { rect } = visible[i];
      const rowTop = rect.top;
      const rowBottom = rect.bottom;
      // Pointer above this item's row → insert here
      if (clientY < rowTop) return i;
      if (clientY <= rowBottom) {
        // Same row — pick by X midpoint
        const midX = rect.left + rect.width / 2;
        const before = isRtl ? clientX > midX : clientX < midX;
        if (before) return i;
      }
    }
    return visible.length;
  }

  for (let i = 0; i < items.length; i += 1) {
    const el = items[i];
    if (el.dataset.dragging === "true") continue;
    const rect = el.getBoundingClientRect();
    if (axis === "x") {
      const mid = rect.left + rect.width / 2;
      if (isRtl) {
        if (clientX > mid) return count;
      } else {
        if (clientX < mid) return count;
      }
    } else {
      if (clientY < rect.top + rect.height / 2) return count;
    }
    count += 1;
  }
  return count;
}

interface ProviderProps {
  children: ReactNode;
  onDragStart?: (snap: DragSnapshot) => void;
  onDragEnd?: (snap: DragSnapshot, dropped: boolean) => void;
  /**
   * Disable the smooth "make room" sibling translation animations.
   * Defaults to false. The provider also auto-disables animations when the
   * OS reports `prefers-reduced-motion: reduce`, regardless of this prop.
   */
  reduceMotion?: boolean;
}

export function DndProvider({ children, onDragStart, onDragEnd, reduceMotion = false }: ProviderProps) {
  const zonesRef = useRef<Map<string, ZoneRegistration>>(new Map());
  const [active, setActive] = useState<DragSnapshot | null>(null);
  const [hover, setHover] = useState<HoverState | null>(null);
  const [overlay, setOverlay] = useState<{ x: number; y: number; node: ReactNode } | null>(null);
  const [systemReducedMotion, setSystemReducedMotion] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return;
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    const update = () => setSystemReducedMotion(mq.matches);
    update();
    mq.addEventListener?.("change", update);
    return () => mq.removeEventListener?.("change", update);
  }, []);

  const animationsEnabled = !reduceMotion && !systemReducedMotion;

  const activeRef = useRef<DragSnapshot | null>(null);
  const hoverRef = useRef<HoverState | null>(null);
  const dropZoneCacheRef = useRef<{ zone: ZoneRegistration; rect: DOMRect } | null>(null);

  useEffect(() => { activeRef.current = active; }, [active]);
  useEffect(() => { hoverRef.current = hover; }, [hover]);

  const registerZone = useCallback((registration: ZoneRegistration) => {
    zonesRef.current.set(registration.id, registration);
    return () => {
      zonesRef.current.delete(registration.id);
    };
  }, []);

  const findZoneAt = useCallback((clientX: number, clientY: number, snap: DragSnapshot) => {
    let result: { zone: ZoneRegistration; rect: DOMRect } | null = null;
    for (const zone of zonesRef.current.values()) {
      if (zone.accepts && !zone.accepts(snap)) continue;
      const rect = zone.element.getBoundingClientRect();
      if (
        clientX >= rect.left &&
        clientX <= rect.right &&
        clientY >= rect.top &&
        clientY <= rect.bottom
      ) {
        if (!result || rect.width * rect.height < result.rect.width * result.rect.height) {
          result = { zone, rect };
        }
      }
    }
    return result;
  }, []);

  // Auto-scroll while dragging near edges of the nearest scrollable ancestor of
  // the active drop-zone. Axis-aware so horizontal lists scroll horizontally.
  useEffect(() => {
    if (!active) return;
    let rafId = 0;
    let lastX = active.clientX;
    let lastY = active.clientY;

    const tick = () => {
      const cache = dropZoneCacheRef.current;
      const axis = (cache?.zone.axis ?? "y") as "x" | "y" | "both";
      const targetEl = cache ? findScrollableAncestor(cache.zone.element, axis) : window;
      const rect = getScrollRect(targetEl);

      let dx = 0;
      let dy = 0;
      if (axis === "y" || axis === "both") {
        const distFromTop = lastY - rect.top;
        const distFromBottom = rect.bottom - lastY;
        if (distFromTop < AUTOSCROLL_EDGE && distFromTop > 0) {
          dy = -((AUTOSCROLL_EDGE - distFromTop) / AUTOSCROLL_EDGE) * AUTOSCROLL_MAX_SPEED;
        } else if (distFromBottom < AUTOSCROLL_EDGE && distFromBottom > 0) {
          dy = ((AUTOSCROLL_EDGE - distFromBottom) / AUTOSCROLL_EDGE) * AUTOSCROLL_MAX_SPEED;
        }
      }
      if (axis === "x" || axis === "both") {
        const distFromLeft = lastX - rect.left;
        const distFromRight = rect.right - lastX;
        if (distFromLeft < AUTOSCROLL_EDGE && distFromLeft > 0) {
          dx = -((AUTOSCROLL_EDGE - distFromLeft) / AUTOSCROLL_EDGE) * AUTOSCROLL_MAX_SPEED;
        } else if (distFromRight < AUTOSCROLL_EDGE && distFromRight > 0) {
          dx = ((AUTOSCROLL_EDGE - distFromRight) / AUTOSCROLL_EDGE) * AUTOSCROLL_MAX_SPEED;
        }
      }
      if (dx !== 0 || dy !== 0) scrollBy(targetEl, dx, dy);
      rafId = requestAnimationFrame(tick);
    };

    const trackPos = (event: PointerEvent) => {
      lastX = event.clientX;
      lastY = event.clientY;
    };
    window.addEventListener("pointermove", trackPos, { passive: true });
    rafId = requestAnimationFrame(tick);

    return () => {
      window.removeEventListener("pointermove", trackPos);
      cancelAnimationFrame(rafId);
    };
  }, [active]);

  const beginDrag = useCallback<DndContextValue["beginDrag"]>((payload, pointerEvent) => {
    const snap: DragSnapshot = {
      id: payload.id,
      data: payload.data,
      width: payload.width,
      height: payload.height,
      offsetX: payload.offsetX,
      offsetY: payload.offsetY,
      sourceTop: payload.sourceTop,
      clientX: pointerEvent.clientX,
      clientY: pointerEvent.clientY,
      sourceLeft: payload.sourceLeft,
      sourceRight: payload.sourceRight,
      sourceBottom: payload.sourceBottom,
      previewNode: payload.preview ? payload.preview() : null,
    };
    setActive(snap);
    setOverlay({
      x: pointerEvent.clientX,
      y: pointerEvent.clientY,
      node: snap.previewNode,
    });
    if (typeof document !== "undefined") {
      document.body.style.cursor = "grabbing";
      document.body.style.userSelect = "none";
    }
    onDragStart?.(snap);

    let dropped = false;

    const handleMove = (event: PointerEvent) => {
      const next: DragSnapshot = { ...snap, clientX: event.clientX, clientY: event.clientY };
      activeRef.current = next;
      setOverlay((prev) => (prev ? { ...prev, x: event.clientX, y: event.clientY } : prev));

      const found = findZoneAt(event.clientX, event.clientY, next);
      dropZoneCacheRef.current = found;

      if (!found) {
        if (hoverRef.current !== null) {
          hoverRef.current = null;
          setHover(null);
        }
        return;
      }

      const zoneAxis = found.zone.axis;
      const axis = (zoneAxis === "x" ? "x" : zoneAxis === "grid" ? "grid" : "y") as "x" | "y" | "grid";
      const sourceIndex = found.zone.getItemIndex?.(next) ?? undefined;
      const center = getDragCenter(next);
      const prevHover = hoverRef.current;
      const sameZoneHover = prevHover && prevHover.zoneId === found.zone.id ? prevHover : null;

      let index: number;
      if (sourceIndex != null && sourceIndex >= 0) {
        // Sibling-based hit test: only update index when the cursor center is
        // actually inside another sibling. When in a gap, KEEP the previous
        // hover index to eliminate flicker as items reflow around the slot.
        const sibling = findSiblingIndexAt(found.zone.element, center.x, center.y);
        if (sibling) {
          const horizontal = axis === "x" || axis === "grid";
          const mid = horizontal
            ? sibling.rect.left + sibling.rect.width / 2
            : sibling.rect.top + sibling.rect.height / 2;
          const coord = horizontal ? center.x : center.y;
          const after = coord > mid;
          index = sibling.visibleIndex + (after ? 1 : 0);
        } else if (sameZoneHover) {
          // Stay put in gaps — prevents flicker back to source position.
          index = sameZoneHover.index;
        } else {
          index = sourceIndex;
        }
      } else {
        index = resolveDropIndex(found.zone.element, center.x, center.y, axis);
      }
      const nextHover: HoverState = { zoneId: found.zone.id, index, sourceIndex };
      if (!prevHover || prevHover.zoneId !== nextHover.zoneId || prevHover.index !== nextHover.index || prevHover.sourceIndex !== nextHover.sourceIndex) {
        hoverRef.current = nextHover;
        setHover(nextHover);
      }
    };

    const cleanup = () => {
      window.removeEventListener("pointermove", handleMove);
      window.removeEventListener("pointerup", handleUp);
      window.removeEventListener("pointercancel", handleCancel);
      window.removeEventListener("keydown", handleKey);
      activeRef.current = null;
      hoverRef.current = null;
      dropZoneCacheRef.current = null;
      setActive(null);
      setHover(null);
      setOverlay(null);
      if (typeof document !== "undefined") {
        document.body.style.cursor = "";
        document.body.style.userSelect = "";
      }
      onDragEnd?.(snap, dropped);
    };

    const handleUp = (event: PointerEvent) => {
      const cache = dropZoneCacheRef.current;
      const finalSnap = { ...(activeRef.current ?? snap), clientX: event.clientX, clientY: event.clientY };
      if (cache) {
        // Trust the last visible hover index — that is exactly what the user
        // saw as the drop target. Recomputing here can land back on the source
        // because items have already shifted to make room for the drop slot.
        const lastHover = hoverRef.current;
        let index: number;
        if (lastHover && lastHover.zoneId === cache.zone.id) {
          index = lastHover.index;
        } else {
          const cAxis = cache.zone.axis;
          const axis = (cAxis === "x" ? "x" : cAxis === "grid" ? "grid" : "y") as "x" | "y" | "grid";
          const center = getDragCenter(finalSnap);
          index = resolveDropIndex(cache.zone.element, center.x, center.y, axis);
        }
        try {
          cache.zone.onDrop({
            item: finalSnap,
            zoneId: cache.zone.id,
            zoneData: cache.zone.data,
            index,
            clientX: event.clientX,
            clientY: event.clientY,
          });
          dropped = true;
        } catch (err) {
          console.error("[dnd] onDrop handler threw:", err);
        }
      }
      cleanup();
    };

    const handleCancel = () => cleanup();
    const handleKey = (event: KeyboardEvent) => {
      if (event.key === "Escape") cleanup();
    };

    window.addEventListener("pointermove", handleMove, { passive: true });
    window.addEventListener("pointerup", handleUp);
    window.addEventListener("pointercancel", handleCancel);
    window.addEventListener("keydown", handleKey);
  }, [findZoneAt, onDragEnd, onDragStart]);

  const value = useMemo<DndContextValue>(() => ({
    active,
    hover,
    animationsEnabled,
    registerZone,
    beginDrag,
  }), [active, hover, animationsEnabled, registerZone, beginDrag]);

  return (
    <DndCtx.Provider value={value}>
      {children}
      {overlay && typeof document !== "undefined" && createPortal(
        (() => {
          const offX = active?.offsetX ?? 0;
          const offY = active?.offsetY ?? 0;
          const w = active?.width ?? 0;
          const h = active?.height ?? 0;
          const vw = typeof window !== "undefined" ? window.innerWidth : 0;
          const vh = typeof window !== "undefined" ? window.innerHeight : 0;
          const rawLeft = overlay.x - offX;
          const rawTop = overlay.y - offY;
          // Clamp so the preview always stays on screen.
          const left = Math.max(4, Math.min(rawLeft, vw - Math.max(w, 40) - 4));
          const top = Math.max(4, Math.min(rawTop, vh - Math.max(h, 24) - 4));
          return (
            <div
              style={{
                position: "fixed",
                left,
                top,
                pointerEvents: "none",
                zIndex: 9999,
                transform: "translateZ(0)",
                opacity: 0.95,
                filter: "drop-shadow(0 12px 24px rgba(0,0,0,0.18))",
              }}
              aria-hidden="true"
            >
              {overlay.node}
            </div>
          );
        })(),
        document.body,
      )}
    </DndCtx.Provider>
  );
}

export function useDndContext(): DndContextValue {
  const ctx = useContext(DndCtx);
  if (!ctx) {
    throw new Error("Custom DnD hooks must be used inside <DndProvider>.");
  }
  return ctx;
}

/**
 * useDraggable — turn any element into a draggable handle.
 *
 * Usage:
 *   const { dragProps, isDragging } = useDraggable({
 *     id: card.id,
 *     data: { cardId: card.id, fromColumnId: col.id },
 *     preview: () => <KanbanCard card={card} />,
 *   });
 *   <div {...dragProps} data-dnd-item="true">…</div>
 *
 * Key behavior:
 *   - Activation distance: drag starts only after pointer moves > N px,
 *     so plain clicks still fire (good for "open card" handlers).
 *   - Pointer Events: works on touch + mouse + pen with no extra code.
 *   - We do NOT call setPointerCapture on the source — the pointer must
 *     stay free to hit-test drop zones underneath.
 *   - Sets `data-dnd-item="true"` so zones can find items, and
 *     `data-dragging="true"` on the source while active so the indexer
 *     skips it.
 */
import { useCallback, useMemo, useRef } from "react";

import { useDndContext } from "./DndContext";
import type { DragData, UseDraggableOptions } from "./types";

export function useDraggable<T extends DragData = DragData>(options: UseDraggableOptions<T>) {
  const { id, data, activationDistance = 5, disabled = false, preview, sourceRef } = options;
  const { beginDrag, active } = useDndContext();
  const startRef = useRef<{ x: number; y: number; pointerId: number } | null>(null);
  // The source element is captured from the PointerEvent target on PointerDown.
  const elementRef = useRef<HTMLElement | null>(null);

  const isDragging = active?.id === id;

  const onPointerDown = useCallback((event: React.PointerEvent<HTMLElement>) => {
    if (disabled) return;
    // Only primary pointer (left mouse / single touch / pen tip).
    if (event.pointerType === "mouse" && event.button !== 0) return;
    // Snapshot the source element on PointerDown so we can pass its size to
    // the provider when the activation distance is crossed.
    elementRef.current = event.currentTarget;
    startRef.current = {
      x: event.clientX,
      y: event.clientY,
      pointerId: event.pointerId,
    };

    const handleMove = (e: PointerEvent) => {
      const start = startRef.current;
      if (!start || start.pointerId !== e.pointerId) return;
      const dx = e.clientX - start.x;
      const dy = e.clientY - start.y;
      if (dx * dx + dy * dy < activationDistance * activationDistance) return;

      // Threshold crossed — promote to a real drag.
      window.removeEventListener("pointermove", handleMove);
      window.removeEventListener("pointerup", handleUp);
      window.removeEventListener("pointercancel", handleUp);
      startRef.current = null;
      const sourceEl = sourceRef?.current ?? elementRef.current;
      const rect = sourceEl?.getBoundingClientRect();
      beginDrag(
        {
          id,
          data,
          preview,
          width: rect?.width ?? 0,
          height: rect?.height ?? 0,
          offsetX: rect ? start.x - rect.left : 0,
          offsetY: rect ? start.y - rect.top : 0,
          sourceLeft: rect?.left,
          sourceTop: rect?.top,
          sourceRight: rect?.right,
          sourceBottom: rect?.bottom,
        },
        e,
      );
    };

    const handleUp = () => {
      window.removeEventListener("pointermove", handleMove);
      window.removeEventListener("pointerup", handleUp);
      window.removeEventListener("pointercancel", handleUp);
      startRef.current = null;
    };

    window.addEventListener("pointermove", handleMove, { passive: true });
    window.addEventListener("pointerup", handleUp);
    window.addEventListener("pointercancel", handleUp);
  }, [activationDistance, beginDrag, data, disabled, id, preview, sourceRef]);

  const dragProps = useMemo(() => ({
    onPointerDown,
    "data-dnd-item": "true" as const,
    "data-dragging": isDragging ? ("true" as const) : ("false" as const),
    // Prevent the browser from also starting a native HTML5 drag (image / link
    // drags) which would conflict with our pointer-based logic.
    draggable: false,
    style: {
      touchAction: "none" as const, // disable scroll gestures while interacting
      userSelect: "none" as const,
      WebkitUserSelect: "none" as const,
    },
  }), [isDragging, onPointerDown]);

  return { dragProps, isDragging };
}

"use client";

/**
 * useDropZone — turn any element into a target for dropped draggables.
 *
 * Usage:
 *   const { zoneProps, isOver, hoverIndex } = useDropZone({
 *     id: column.id,
 *     data: { columnId: column.id },
 *     onDrop: ({ item, index }) => moveCard(item.data.cardId, column.id, index),
 *   });
 *   <div ref={zoneProps.ref}>…</div>
 *
 * Key behavior:
 *   - Registers the zone with the provider so the global pointermove handler
 *     can hit-test it (no per-zone listeners → no flicker storms).
 *   - Returns `hoverIndex` (computed midpoint index) when this zone is the
 *     active hover target, else null. Use it to render a single drop indicator
 *     at the right slot.
 *   - The zone callback fires AT MOST ONCE per drop and never on cancels.
 */
import { useCallback, useEffect, useMemo, useRef } from "react";
import { useDndContext } from "./DndContext";
import type { DragData, DropResult, UseDropZoneOptions } from "./types";

export function useDropZone<TZone extends DragData = DragData, TItem extends DragData = DragData>(
  options: UseDropZoneOptions<TZone, TItem>,
) {
  const { id, data, accepts, onDrop, disabled = false, axis = "y", getItemIndex } = options;
  const { active, hover, animationsEnabled, registerZone } = useDndContext();
  const elementRef = useRef<HTMLElement | null>(null);

  // Latest callbacks/data without forcing re-registration on every render.
  const handlersRef = useRef({ accepts, onDrop, data, getItemIndex });
  useEffect(() => {
    handlersRef.current = { accepts, onDrop, data, getItemIndex };
  }, [accepts, onDrop, data, getItemIndex]);

  const ref = useCallback((node: HTMLElement | null) => {
    elementRef.current = node;
  }, []);

  // Register / unregister whenever the actual DOM node or id changes — but
  // NOT on every onDrop change, since we read those from handlersRef.
  useEffect(() => {
    if (disabled) return;
    const node = elementRef.current;
    if (!node) return;

    const unregister = registerZone({
      id,
      element: node,
      get data() { return (handlersRef.current.data ?? {}) as DragData; },
      accepts: (drag) => {
        const fn = handlersRef.current.accepts;
        return fn ? fn(drag as never) : true;
      },
      onDrop: (result) => {
        handlersRef.current.onDrop(result as DropResult<TItem, TZone>);
      },
      getItemIndex: (drag) => handlersRef.current.getItemIndex?.(drag as never) ?? null,
      axis,
    });
    return unregister;
    // We intentionally re-register if `disabled` flips. The element ref is set
    // by `ref` callback before this effect runs (React commits refs first).
  }, [disabled, id, registerZone, axis]);

  const isOver = hover?.zoneId === id;
  const hoverIndex = isOver ? hover.index : null;

  const zoneProps = useMemo(() => ({
    ref,
    "data-dnd-zone": id,
    "data-dnd-over": isOver ? ("true" as const) : ("false" as const),
  }), [id, isOver, ref]);

  /**
   * Returns the inline style each rendered item in this zone should spread to
   * smoothly translate out of the way when a drag hovers over this zone, so
   * a real-sized gap opens at the insertion point — matching the dragged
   * card's exact dimensions, not a thin indicator bar.
   *
   *   - axis "y" → translateY by the dragged item's height (+ gap).
   *   - axis "x" → translateX (negated in RTL containers).
   *
   * Returns `{}` when the zone is not the hover target, when there is no
   * active drag, or when animations are disabled (reduce-motion).
   */
  const getItemSlotStyle = useCallback(
    (itemIndex: number): React.CSSProperties => {
      if (!isOver || hoverIndex == null || !active) return {};
      // The drag source collapses to height 0 (handled by the caller), so we
      // can treat every drop the same way: shift every sibling at-or-after
      // hoverIndex by exactly one slot. This eliminates the "two cards in the
      // same row" overlap that happened with sourceIndex-based shifting.
      if (itemIndex < hoverIndex) return {};
      const gap = 8;
      const transition = animationsEnabled
        ? "transform 200ms cubic-bezier(0.2, 0, 0, 1)"
        : "none";
      if (axis === "x") {
        const dx = active.width + gap;
        const isRtl = elementRef.current
          ? window.getComputedStyle(elementRef.current).direction === "rtl"
          : false;
        return {
          transform: `translate3d(${isRtl ? -dx : dx}px, 0, 0)`,
          transition,
          willChange: "transform",
        };
      }
      return {
        transform: `translate3d(0, ${active.height + gap}px, 0)`,
        transition,
        willChange: "transform",
      };
    },
    [active, animationsEnabled, axis, hover, hoverIndex, id, isOver],
  );

  /** Size of the "ghost slot" placeholder rendered at the insertion point. */
  const slotSize = useMemo(
    () => ({ width: active?.width ?? 0, height: active?.height ?? 0 }),
    [active?.width, active?.height],
  );

  return {
    zoneProps,
    isOver,
    hoverIndex,
    isDragging: !!active,
    getItemSlotStyle,
    slotSize,
    animationsEnabled,
  };
}

/**
 * Visual slot indicator rendered at the computed insertion index inside a zone.
 * Stable identity — same element, same key, no animation churn — eliminates the
 * "indicator flicker" that pure HTML5 DnD produces. Smoothly fades + scales in
 * so reorder feels animated even though we never re-mount items.
 */
import { cn } from "@/lib/utils";

interface Props {
  className?: string;
  /** Layout axis of the parent zone. Affects shape (horizontal bar vs vertical bar). */
  axis?: "x" | "y";
  /** When provided, the indicator renders as a real-sized "ghost slot" matching
   *  the dragged item's dimensions instead of a thin bar. */
  size?: { width: number; height: number };
  /** Disable the fade/zoom animation (used in reduce-motion mode). */
  animated?: boolean;
}

export function DropIndicator({ className, axis = "y", size, animated = true }: Props) {
  // Sized ghost slot — opens a real gap matching the dragged card. This is
  // what gives the board the "card slides into place" feel from the demo.
  if (size && size.width > 0 && size.height > 0) {
    return (
      <div
        aria-hidden="true"
        className={cn(
          "rounded-md border-2 border-dashed border-primary/50 bg-primary/10",
          animated && "animate-in fade-in zoom-in-95 duration-150",
          className,
        )}
        style={{ width: size.width, height: size.height }}
      />
    );
  }
  return (
    <div
      aria-hidden="true"
      className={cn(
        axis === "y" && "h-2 w-full rounded-sm border border-dashed border-primary/60 bg-primary/15",
        axis === "x" && "h-full min-h-8 w-2 rounded-sm border border-dashed border-primary/60 bg-primary/15 self-stretch",
        animated && "animate-in fade-in zoom-in-95 duration-150",
        className,
      )}
    />
  );
}

/**
 * Type contracts for the custom Pointer DnD library.
 *
 * The library is **pointer-event based** (not HTML5 native drag) so it:
 *   - never shows the OS ghost preview (no flicker)
 *   - works identically on touch & mouse via PointerEvents
 *   - lets us render a fully styled React overlay at the cursor
 *   - can autoscroll containers and cancel via Escape
 */

/** Anything the consumer wants to attach to a draggable. Stays type-safe via generics. */
export type DragData = Record<string, unknown>;

/** Snapshot of an active drag — passed to drop handlers. */
export interface DragSnapshot<T extends DragData = DragData> {
  /** Stable id of the dragged item. */
  id: string;
  /** Caller-supplied metadata (e.g. {cardId, fromColumnId, fromLane}). */
  data: T;
  /** Current pointer client coords. */
  clientX: number;
  clientY: number;
  /**
   * Bounding-box size of the dragged source element captured at drag start.
   * Used by drop zones to translate sibling items by the matching dimension
   * so a real "make room" gap opens, not just a thin indicator bar.
   */
  width: number;
  height: number;
  /** Pointer offset inside the source element at drag start. Keeps overlay under the cursor. */
  offsetX: number;
  offsetY: number;
  /** Source element bounds captured at drag start, used to avoid premature same-zone reflow. */
  sourceLeft?: number;
  sourceTop?: number;
  sourceRight?: number;
  sourceBottom?: number;
  /** Rendered drag preview, also reusable by consumers as a matching drop shadow. */
  previewNode?: React.ReactNode;
}

/** What a drop zone receives on a successful drop. */
export interface DropResult<TItem extends DragData = DragData, TZone extends DragData = DragData> {
  item: DragSnapshot<TItem>;
  zoneId: string;
  zoneData: TZone;
  /** Insertion index inside the zone (0..n) computed from pointer Y midpoints. */
  index: number;
  /** Pointer position at drop. */
  clientX: number;
  clientY: number;
}

/** Internal hover descriptor — shared via context so zones can render a single indicator. */
export interface HoverState {
  zoneId: string;
  index: number;
  /** Where the active item currently sits if it belongs to this same zone. */
  sourceIndex?: number;
}

/** Element registration for a drop zone (registered via useDropZone). */
export interface ZoneRegistration<TZone extends DragData = DragData> {
  id: string;
  data: TZone;
  element: HTMLElement;
  /** Should this zone accept the current drag? Defaults to true. */
  accepts?: (drag: DragSnapshot) => boolean;
  onDrop: (result: DropResult) => void;
  /** Return the active draggable's current index in this zone, or null if it is not from this zone. */
  getItemIndex?: (drag: DragSnapshot) => number | null;
  /**
   * Layout axis for index-resolution and edge autoscroll.
   *   "y"    — vertical list (default; index from Y midpoints)
   *   "x"    — horizontal list (index from X midpoints, X-axis autoscroll)
   *   "both" — autoscroll on either axis (kanban board scroll containers)
   *   "grid" — wrapping grid; index resolved row-then-column (Y, then X)
   */
  axis?: "x" | "y" | "both" | "grid";
}

export interface DndContextValue {
  /** Active drag snapshot, or null when idle. */
  active: DragSnapshot | null;
  /** Where the cursor is currently hovering (zone + computed insertion index). */
  hover: HoverState | null;
  /** Animations are honored by the lib. False when user opts out OR when the
   *  OS reports `prefers-reduced-motion: reduce`. */
  animationsEnabled: boolean;
  /** Register / unregister a drop zone. */
  registerZone: (registration: ZoneRegistration) => () => void;
  /** Begin a drag from a draggable. */
  beginDrag: (
    payload: {
      id: string;
      data: DragData;
      preview?: () => React.ReactNode;
      /** Size of the source element. Used to open a real-sized gap. */
      width: number;
      height: number;
      /** Pointer offset inside the source element. */
      offsetX: number;
      offsetY: number;
      sourceLeft?: number;
      sourceTop?: number;
      sourceRight?: number;
      sourceBottom?: number;
    },
    pointerEvent: PointerEvent,
  ) => void;
}

/** Options for useDraggable. */
export interface UseDraggableOptions<T extends DragData = DragData> {
  id: string;
  data: T;
  /** Pixels the pointer must move before a drag actually starts (default 5). */
  activationDistance?: number;
  /** Disable the draggable entirely. */
  disabled?: boolean;
  /** Optional custom React preview rendered inside the overlay. */
  preview?: () => React.ReactNode;
  /** Optional full source element to measure when the pointer handle is not the visual item. */
  sourceRef?: { current: HTMLElement | null };
}

/** Options for useDropZone. */
export interface UseDropZoneOptions<TZone extends DragData = DragData, TItem extends DragData = DragData> {
  id: string;
  data?: TZone;
  accepts?: (drag: DragSnapshot<TItem>) => boolean;
  onDrop: (result: DropResult<TItem, TZone>) => void;
  /** Disable the zone entirely. */
  disabled?: boolean;
  /** Layout axis. Defaults to "y" (vertical list). */
  axis?: "x" | "y" | "both" | "grid";
  /** Return active draggable's current index in this zone; enables same-column make-room animation. */
  getItemIndex?: (drag: DragSnapshot<TItem>) => number | null;
}

/**
 * Custom Pointer DnD — global styles.
 *
 * - Smooth transform transitions on items inside an active drop zone so that
 *   the visual gap created by <DropIndicator/> appearing/disappearing slides
 *   smoothly rather than snapping.
 * - The dragged item itself is excluded (it's already pinned to the cursor by
 *   the overlay portal).
 */
[data-dnd-zone="true"], [data-dnd-zone] {
  /* No-op selector — keeps Tailwind purger from dropping the data attribute. */
}

/* Smooth slide for siblings while a drag is in progress. */
[data-dnd-over="true"] [data-dnd-item="true"]:not([data-dragging="true"]) {
  transition: transform 180ms cubic-bezier(0.2, 0, 0, 1);
}

/* Visual treatment for the dragged source — the overlay shows the real card. */
[data-dnd-item="true"][data-dragging="true"] {
  transition: opacity 100ms ease-out;
}
